using namespace std;

int main() {
    int n, sum = 0;
    cout << "Enter number: ";
    cin >> n;

    n = abs(n); // Simpler way to handle negatives

    while (n > 0) {
        sum += n % 10; // Add last digit
        n /= 10;       // Remove last digit
    }

    cout << sum << endl;
    return 0;
}
```

### 2. The "One-Liner" Loop (More Concise)
You can put the logic inside the `for` loop header to make it very short.

```cpp
#include <iostream>
using namespace std;

int main() {
    int n, sum = 0;
    cin >> n;

    for (n = abs(n); n > 0; n /= 10) 
        sum += n % 10;

    cout << sum;
}
```

### 3. The Most Optimized (String Input)
If the number is **extremely large** (larger than an `int` can hold, like 50 digits), use a string. This is faster because it avoids division and modulo math.

```cpp
#include <iostream>
#include <string>
using namespace std;

int main() {
    string n;
    int sum = 0;
    cin >> n;

    for (char c : n) {
        if (isdigit(c)) // Ignores '-' sign automatically
            sum += c - '0'; // Converts char '5' to int 5
    }

    cout << sum;
}
```

